def gen(rng, size):
    n = max(2, size)
    arr = [rng.randint(0, 100000)]
    while len([x for x in arr if x is not None]) < 2 or len(arr) < n:
        arr.append(rng.randint(0, 100000) if rng.random() < 0.85 else None)
        if len(arr) >= n and len([x for x in arr if x is not None]) >= 2:
            break
    return [arr]

