class Solution:
    def maxAncestorDiff(self, root):
        # Brute force: for each node, scan its full subtree and take the
        # extreme value-difference with every descendant.
        best = [0]
        def descendants(node):
            if node is None:
                return []
            return [node.val] + descendants(node.left) + descendants(node.right)
        def walk(node):
            if node is None:
                return
            ds = descendants(node.left) + descendants(node.right)
            for d in ds:
                best[0] = max(best[0], abs(node.val - d))
            walk(node.left)
            walk(node.right)
        walk(root)
        return best[0]

