class Solution:
    def maxAncestorDiff(self, root):
        self.best = 0
        def dfs(node, lo, hi):
            if node is None:
                self.best = max(self.best, hi - lo)
                return
            lo = min(lo, node.val)
            hi = max(hi, node.val)
            dfs(node.left, lo, hi)
            dfs(node.right, lo, hi)
        dfs(root, root.val, root.val)
        return self.best

