var maxAncestorDiff = function(root) {
    let best = 0;
    function dfs(node, lo, hi) {
        if (!node) {
            best = Math.max(best, hi - lo);
            return;
        }
        lo = Math.min(lo, node.val);
        hi = Math.max(hi, node.val);
        dfs(node.left, lo, hi);
        dfs(node.right, lo, hi);
    }
    dfs(root, root.val, root.val);
    return best;
};
